          (Swift_id IS NOT NULL AND Cheque_id IS NULL AND Cripto_id IS NULL AND Efectivo_id IS NULL AND PayPal_id IS NULL AND TarjCred_id IS NULL AND TarjDeb_id IS NULL) OR
          (TarjCred_id IS NOT NULL AND Cheque_id IS NULL AND Cripto_id IS NULL AND Efectivo_id IS NULL AND PayPal_id IS NULL AND Swift_id IS NULL AND TarjDeb_id IS NULL) OR
          (TarjDeb_id IS NOT NULL AND Cheque_id IS NULL AND Cripto_id IS NULL AND Efectivo_id IS NULL AND PayPal_id IS NULL AND Swift_id IS NULL AND TarjCred_id IS NULL)
          )
    );

    CREATE TABLE PagoNatural (
        idPagoNatural   NUMERIC NOT NULL UNIQUE,
        Compra_idCompra NUMERIC NOT NULL,

        Cheque_id       NUMERIC,
        Cripto_id       NUMERIC,
        Efectivo_id     NUMERIC,
        PayPal_id       NUMERIC,
        Swift_id        NUMERIC,
        TarjCred_id     NUMERIC,
        TarjDeb_id      NUMERIC,

        CONSTRAINT pk_pago_natural_01 PRIMARY KEY (idPagoNatural, Compra_idCompra),

        CONSTRAINT arc_pago_natural_metodo CHECK (
         (Cheque_id IS NOT NULL AND Cripto_id IS NULL AND Efectivo_id IS NULL AND PayPal_id IS NULL AND Swift_id IS NULL AND TarjCred_id IS NULL AND TarjDeb_id IS NULL) OR
         (Cripto_id IS NOT NULL AND Cheque_id IS NULL AND Efectivo_id IS NULL AND PayPal_id IS NULL AND Swift_id IS NULL AND TarjCred_id IS NULL AND TarjDeb_id IS NULL) OR
         (Efectivo_id IS NOT NULL AND Cheque_id IS NULL AND Cripto_id IS NULL AND PayPal_id IS NULL AND Swift_id IS NULL AND TarjCred_id IS NULL AND TarjDeb_id IS NULL) OR
         (PayPal_id IS NOT NULL AND Cheque_id IS NULL AND Cripto_id IS NULL AND Efectivo_id IS NULL AND Swift_id IS NULL AND TarjCred_id IS NULL AND TarjDeb_id IS NULL) OR
         (Swift_id IS NOT NULL AND Cheque_id IS NULL AND Cripto_id IS NULL AND Efectivo_id IS NULL AND PayPal_id IS NULL AND TarjCred_id IS NULL AND TarjDeb_id IS NULL) OR
         (TarjCred_id IS NOT NULL AND Cheque_id IS NULL AND Cripto_id IS NULL AND Efectivo_id IS NULL AND PayPal_id IS NULL AND Swift_id IS NULL AND TarjDeb_id IS NULL) OR
         (TarjDeb_id IS NOT NULL AND Cheque_id IS NULL AND Cripto_id IS NULL AND Efectivo_id IS NULL AND PayPal_id IS NULL AND Swift_id IS NULL AND TarjCred_id IS NULL)
         )
    );

